import SwiftUI
import AIUsagesTrackersLib

/// Root view for the usage details popover.
/// Displays a scrollable list of account cards grouped by vendor, with a footer.
struct UsageDetailsView: View {
    let store: UsageStore
    let onQuit: () -> Void

    private static let maxPopoverHeight: CGFloat = 480
    private static let popoverWidth: CGFloat = 320

    var body: some View {
        VStack(spacing: 0) {
            if sortedEntries.isEmpty {
                emptyState
            } else {
                ScrollView {
                    LazyVStack(spacing: 8) {
                        ForEach(Array(sortedEntries.enumerated()), id: \.offset) { _, entry in
                            AccountCardView(
                                entry: entry,
                                showActiveBadge: hasMultipleAccountsForVendor(entry.vendor)
                            )
                        }
                    }
                    .padding(12)
                }
                .frame(maxHeight: Self.maxPopoverHeight)
            }

            Divider()

            footer
        }
        .frame(width: Self.popoverWidth)
    }

    // MARK: - Sorting

    /// Group by vendor, active first within each group, then alphabetical by account.
    private var sortedEntries: [VendorUsageEntry] {
        store.entries.sorted { lhs, rhs in
            if lhs.vendor.rawValue != rhs.vendor.rawValue {
                return lhs.vendor.rawValue < rhs.vendor.rawValue
            }
            if lhs.isActive != rhs.isActive {
                return lhs.isActive
            }
            return lhs.account.rawValue < rhs.account.rawValue
        }
    }

    private func hasMultipleAccountsForVendor(_ vendor: Vendor) -> Bool {
        store.entries.filter { $0.vendor == vendor }.count > 1
    }

    // MARK: - Subviews

    private var emptyState: some View {
        VStack(spacing: 8) {
            Text("No usage data")
                .font(.system(size: 12, weight: .medium))
                .foregroundStyle(.secondary)
            Text("Waiting for data...")
                .font(.system(size: 11))
                .foregroundStyle(.tertiary)
        }
        .frame(maxWidth: .infinity)
        .padding(.vertical, 32)
    }

    private var footer: some View {
        HStack {
            Text("AI Usages Tracker")
                .font(.system(size: 10))
                .foregroundStyle(.tertiary)
            Spacer()
            Button("Quit") {
                onQuit()
            }
            .keyboardShortcut("q")
            .controlSize(.small)
        }
        .padding(.horizontal, 12)
        .padding(.vertical, 8)
    }
}

