import SwiftUI
import AIUsagesTrackersLib

/// Displays a time-window metric: name, gauge bar with theoretical marker,
/// percentage, remaining time, and next reset date.
struct TimeWindowMetricRow: View {
    let name: String
    let resetAt: ISODate
    let windowDuration: DurationMinutes
    let usagePercent: UsagePercent

    private var actualFraction: Double {
        Double(usagePercent.rawValue) / 100.0
    }

    private var theoreticalFraction: Double {
        guard let resetDate = resetAt.date else { return 0 }
        let windowSeconds = Double(windowDuration.rawValue) * 60
        guard windowSeconds > 0 else { return 0 }
        let windowStart = resetDate.addingTimeInterval(-windowSeconds)
        let elapsed = Date().timeIntervalSince(windowStart)
        return min(max(elapsed / windowSeconds, 0), 1)
    }

    private var remainingText: String {
        guard let resetDate = resetAt.date else { return "0m" }
        let totalSeconds = Int(resetDate.timeIntervalSince(Date()))
        guard totalSeconds > 0 else { return "0m" }

        let secondsPerMinute = 60
        let secondsPerHour = 3600
        let secondsPerDay = 86400

        let days = totalSeconds / secondsPerDay
        let hours = (totalSeconds % secondsPerDay) / secondsPerHour
        let minutes = (totalSeconds % secondsPerHour) / secondsPerMinute

        var parts: [String] = []
        if days > 0 { parts.append("\(days)d") }
        if hours > 0 { parts.append("\(hours)h") }
        if minutes > 0 || parts.isEmpty { parts.append("\(minutes)m") }
        return parts.joined(separator: " ")
    }

    private var resetDateText: String {
        guard let resetDate = resetAt.date else { return "--" }
        let formatter = DateFormatter()
        formatter.dateFormat = "MMM d, HH:mm"
        return formatter.string(from: resetDate)
    }

    var body: some View {
        VStack(alignment: .leading, spacing: 4) {
            HStack {
                Text(name.capitalized)
                    .font(.system(size: 11, weight: .medium))
                    .foregroundStyle(.secondary)
                Spacer()
                Text("\(usagePercent.rawValue)%")
                    .font(.system(size: 11, weight: .semibold).monospacedDigit())
            }

            GaugeBar(actual: actualFraction, theoretical: theoreticalFraction)

            HStack {
                Text(remainingText)
                    .font(.system(size: 10).monospacedDigit())
                    .foregroundStyle(.tertiary)
                Spacer()
                Text("resets \(resetDateText)")
                    .font(.system(size: 10))
                    .foregroundStyle(.tertiary)
            }
        }
    }
}

