/// The theoretical marker is a thin vertical tick showing expected consumption based on elapsed time.
struct GaugeBar: View {
    let actual: Double
    let theoretical: Double

    private static let barHeight: CGFloat = 6
    private static let markerWidth: CGFloat = 1.5
    private static let cornerRadius: CGFloat = 3

    var body: some View {
        GeometryReader { geo in
            let width = geo.size.width

            ZStack(alignment: .leading) {
                // Track
                RoundedRectangle(cornerRadius: Self.cornerRadius)
                    .fill(.quaternary)

                // Actual fill
                RoundedRectangle(cornerRadius: Self.cornerRadius)
                    .fill(fillColor)
                    .frame(width: width * clamp(actual))

                // Theoretical marker tick
                if theoretical > 0 {
                    RoundedRectangle(cornerRadius: Self.markerWidth / 2)
                        .fill(.secondary)
                        .frame(width: Self.markerWidth, height: Self.barHeight + 4)
                        .offset(x: width * clamp(theoretical) - Self.markerWidth / 2)
                }
            }
        }
        .frame(height: Self.barHeight)
    }

    private var fillColor: Color {
        let clamped = clamp(actual)
        if clamped >= 0.9 { return .red }
        if clamped >= 0.75 { return .orange }
        return .accentColor
    }

    private func clamp(_ value: Double) -> CGFloat {
        CGFloat(min(max(value, 0), 1))
    }
}

import Foundation
import Testing
@testable import AIUsagesTrackersLib

// MARK: - Test doubles

/// A mock FileWatching that lets tests push arbitrary Data payloads.
struct MockFileWatcher: FileWatching {
    let stream: AsyncStream<Data>
    let continuation: AsyncStream<Data>.Continuation

    init() {
        var cont: AsyncStream<Data>.Continuation!
        stream = AsyncStream { cont = $0 }
        continuation = cont
    }

    func changes() -> AsyncStream<Data> { stream }

    func send(_ data: Data) { continuation.yield(data) }
    func finish() { continuation.finish() }
}

/// A clock fixed at a given date, for deterministic remaining-time formatting.
struct FixedClock: ClockProvider {
    let date: Date
    init(_ date: Date) { self.date = date }
    func now() -> Date { date }
}

// MARK: - Helpers

private func makeUsagesJSON(
    vendor: String = "claude",
    account: String = "user@example.com",
    isActive: Bool = true,
    metrics: [[String: Any]] = []
) -> Data {
    let entry: [String: Any] = [
        "vendor": vendor,
        "account": account,
        "isActive": isActive,
        "metrics": metrics,
    ]
    let root: [String: Any] = ["usages": [entry]]
    return try! JSONSerialization.data(withJSONObject: root)
}

private func timeWindowMetric(
    name: String = "session",
    resetAt: String = "2026-04-17T15:00:00Z",
    windowDurationMinutes: Int = 300,
    usagePercent: Int = 42
) -> [String: Any] {
    [
        "type": "time-window",
        "name": name,
        "resetAt": resetAt,
        "windowDurationMinutes": windowDurationMinutes,
        "usagePercent": usagePercent,
    ]
}

private func payAsYouGoMetric(
    name: String = "monthly",
    currentAmount: Double = 12.50,
    currency: String = "USD"
) -> [String: Any] {
    [
        "type": "pay-as-you-go",
        "name": name,
        "currentAmount": currentAmount,
        "currency": currency,
    ]
}

